SELECT p.id, p.seller_id, u.nickname AS seller_nickname, u.avatar AS seller_avatar, p.category_id, c.name AS category_name, p.title, p.description, p.price, p.currency, p.stock, p.image, p.images, p.shipping_address, p.status, p.audit_status, p.audit_remark, p.risk_level, p.restricted_flag, p.view_count, p.create_time FROM product p LEFT JOIN user u ON p.seller_id = u.id LEFT JOIN category c ON p.category_id = c.id WHERE p.deleted = 0
AND (p.category_id = #{categoryId} OR p.category_id IN (SELECT id FROM category WHERE parent_id = #{categoryId} AND deleted = 0))
AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%'))
AND p.status = #{status}
AND p.stock > 0
AND p.seller_id = #{sellerId}
ORDER BY p.create_time DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM product p WHERE p.deleted = 0
AND (p.category_id = #{categoryId} OR p.category_id IN (SELECT id FROM category WHERE parent_id = #{categoryId} AND deleted = 0))
AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%'))
AND p.status = #{status}
AND p.stock > 0
AND p.seller_id = #{sellerId}
